127	class CarKeySessionAccesser: NSObject, CarKeySessionAccesserProtocol {
128	    
129	    static func withTimeout<R>(
130	        seconds: TimeInterval,
131	        operation: @escaping () async throws -> R
132	    ) async throws -> R {
133	        try await withThrowingTaskGroup(of: R.self) { group in
134	            group.addTask { try await operation() }
135	            
136	            group.addTask {
137	                try await Task.sleep(nanoseconds: UInt64(seconds * 1_000_000_000))
138	                throw CarKeySessionError.TaskTimedOut
139	            }
140	            
141	            let result = try await group.next()!
142	            group.cancelAll()
143	            return result
144	        }
145	    }
146	    
147	    var carKeySession: CarKeyRemoteControlSession?
148	    var vehicleIdentifier: String
149	    var supportedFunctions: [FunctionIdentifier]?
150	    var mockExcpetionType: CarKeyExceptionType = .None
151	    
152	    let semaphore = DispatchSemaphore(value: 1)
153	    var stateSubject: PassthroughSubject<CarKeySessionState, Never> = .init()
154	    var _state: CarKeySessionState = .NotConnected
155	    var state: CarKeySessionState {
156	        get {
157	            semaphore.wait()
158	            defer { semaphore.signal() }
159	            return _state
160	        }
161	        set {
162	            semaphore.wait()
163	            guard _state != newValue else {
164	                semaphore.signal()
165	                return
166	            }
167	            Log.i("Setting value to \(newValue)")
168	            _state = newValue
169	            semaphore.signal()
170	            stateSubject.send(newValue)
171	        }
172	    }
173	    
174	    private var endSessionCancellable: AnyCancellable?
175	    
176	    weak var carKeyEventDelegate: CarKeySessionEventDelegate?
177	    
178	    public init(vehicleIdentifier: String, delegate: CarKeySessionEventDelegate?) {
179	        self.vehicleIdentifier = vehicleIdentifier
180	        self.carKeyEventDelegate = delegate
181	        super.init()
182	        self.state = .NotConnected
183	        self.addObserver()
184	        Log.i(tag: "carKeySession", "init,vehicleIdentifier= \(vehicleIdentifier)")
185	    }
186	    
187	    deinit {
188	        Log.i(tag: "carKeySession", "deinit,vehicleIdentifier= \(vehicleIdentifier)")
189	        carKeyEventDelegate = nil
190	        // 确保清理所有资源
191	        if carKeySession != nil {
192	            endCarKeySession(nil)
193	        }
194	    }
195	    
196	    private func addObserver() {
197	        NotificationCenter.default.addObserver(self, selector: #selector(mockExceptionTypeChanged), name: NSNotification.Name(rawValue: "CarKeySessionMockExceptionTypeChanged"), object: nil)
198	    }
199	    
200	    @objc func mockExceptionTypeChanged(noti: Notification) {
201	        let exceptionType: Int = noti.userInfo?["exceptionType"] as? Int ?? 0
202	        self.mockExcpetionType = CarKeyExceptionType.init(rawValue: exceptionType) ?? .None
203	    }
204	    
205	    public func startCarKeySession(timeOut: TimeInterval, _ complete: @escaping ((CarKeySessionError) -> Void)) {
206	        if state == .Connecting {
207	            complete(CarKeySessionError.CarKeySessionIsConnecting)
208	            return
209	        }
210	        if state == .Disconnecting {
211	            complete(CarKeySessionError.CarKeySessionIsDisconnecting)
212	            return
213	        }
214	        self.state = .Connecting
215	        if let carKeySession = self.carKeySession {
216	            let result = refreshRealTimeCarKeySessionState(carKeySession: carKeySession)
217	            self.state = result.0
218	            complete(result.1)
219	        } else {
220	            Log.i(tag: "carKeySession", "startCarKeySession")
221	            let monitorTask = Task.detached { [weak self] in
222	                guard let self = self else {
223	                    return
224	                }
225	                try await Task.sleep(nanoseconds: UInt64((timeOut + 3) * 1_000_000_000))
226	                // 如果执行到这里，说明内层阻塞了
227	                Log.i(tag: "carKeySession", "block exception occurred！")
228	                self.carKeyEventDelegate?.reportBlockingException(data: CarKeyExceptionObj(cccVid: self.vehicleIdentifier, exceptionType: .Block, sessionError: .Block))
229	            }
230	            Task.detached(priority: .userInitiated) { [weak self] in
231	                guard let self = self else {
232	                    complete(CarKeySessionError.Unknown)
233	                    return
234	                }
235	                do {
236	                    Log.i(tag: "carKeySession", "do carkeySession start")
237	                    var observeTimeOut: TimeInterval = timeOut
238	                    if self.mockExcpetionType == .Block {
239	                        observeTimeOut = 10000
240	                    }
241	                    let result = try await CarKeySessionAccesser.withTimeout(seconds: observeTimeOut) {
242	                        if self.mockExcpetionType == .Block {
243	                            try await Task.sleep(nanoseconds: UInt64(observeTimeOut * 1_000_000_000))
244	                        } else if self.mockExcpetionType == .Timeout {
245	                            try await Task.sleep(nanoseconds: UInt64((observeTimeOut + 2) * 1_000_000_000))
246	                        } else if self.mockExcpetionType == .Error {
247	                            throw CarKeySessionError.RequestTimedOut
248	                        }
249	                        return try await CarKeyRemoteControl.start(delegate: self)
250	                    }
251	                    Log.i(tag: "carKeySession", "do carkeySession end")
252	                    self.carKeySession = result
253	                    let connectState = refreshRealTimeCarKeySessionState(carKeySession: result)
254	                    self.state = connectState.0
255	                    complete(connectState.1)
256	                    monitorTask.cancel()
257	                    self.carKeyEventDelegate?.reportBlockingException(data: CarKeyExceptionObj(cccVid: self.vehicleIdentifier, exceptionType: .None, sessionError: .None))
258	                } catch CarKeySessionError.TaskTimedOut {
259	                    Log.i("carKeySession", "start carkeySession timeout")
260	                    monitorTask.cancel()
261	                    complete(.TaskTimedOut)
262	                    self.carKeyEventDelegate?.reportBlockingException(data: CarKeyExceptionObj(cccVid: self.vehicleIdentifier, exceptionType: .Timeout, sessionError: .TaskTimedOut))
263	                } catch {
264	                    Log.i(tag: "carKeySession", "start session error occurred: \(error.localizedDescription)")
265	                    monitorTask.cancel()
266	                    var sessionError: CarKeySessionError = .Unknown
267	                    if let carKeyError = error as? CarKeyErrorCode {
268	                        if carKeyError == .ClientInBackground {
269	                            sessionError = .ClientInBackground
270	                        } else if carKeyError == .Internal {
271	                            sessionError = .Unknown
272	                        } else if carKeyError == .VehicleNotConnected {
273	                            sessionError = .BleIsNotConnected
274	                        } else if carKeyError == .SessionNotActive {
275	                            sessionError = .SessionNotActive
276	                        }  else if carKeyError == .SecurityViolation {
277	                            sessionError = .SecurityViolation
278	                        } else if carKeyError == .RequestTimedOut {
279	                            sessionError = .RequestTimedOut
280	                        } else {
281	                            sessionError = .Unknown
282	                        }
283	                    } else {
284	                        sessionError = .Unknown
285	                    }
286	                    complete(sessionError)
287	                    self.carKeyEventDelegate?.reportBlockingException(data: CarKeyExceptionObj(cccVid: self.vehicleIdentifier, exceptionType: .Error, sessionError: sessionError))
288	                }
289	            }
290	        }
291	    }
292	    
293	    func endCarKeySession(_ completion: ((CarKeySessionError) -> Void)?) {
294	        if state != CarKeySessionState.Connecting {
295	            let result = executeEndSessionOperation()
296	            completion?(result)
297	            return
298	        }
299	        self.endSessionCancellable = self.stateSubject
300	            .filter { $0 != CarKeySessionState.Connecting }
301	            .first()
302	            .sink { [weak self] newState in
303	                guard let self = self else {
304	                    completion?(.Unknown)
305	                    return
306	                }
307	                self.endSessionCancellable?.cancel()
308	                self.endSessionCancellable = nil
309	                let result = self.executeEndSessionOperation()
310	                completion?(result)
311	            }
312	    }
313	    
314	    private func executeEndSessionOperation() -> CarKeySessionError {
315	        guard let carKeySession = self.carKeySession else {
316	            Log.i(tag: "carKeySession", "car key session is nil")
317	            self.state = .NotConnected
318	            return CarKeySessionError.CarKeySessionIsNil
319	        }
320	        self.state = .Disconnecting
321	        do {
322	            Log.i(tag: "carKeySession", "end key session")
323	            try carKeySession.end()
324	            self.carKeySession = nil
325	            self.state = .NotConnected
326	            return CarKeySessionError.None
327	        } catch let error as NSError {
328	            self.carKeySession = nil
329	            self.state = .NotConnected
330	            Log.i(tag: "carKeySession", "end session error occurred: \(error.localizedDescription)")
331	            return CarKeySessionError.Unknown
332	        }
333	    }
334	    
335	    public func sendPassthroughtData(data: Data, timeOut: TimeInterval, _ complete: @escaping ((CarKeySessionError) -> Void)) {
336	        guard let carkeySession = self.carKeySession else {
337	            complete(.CarKeySessionIsNil)
338	            return
339	        }
340	        if self.vehicleIdentifier == "" {
341	            complete(.VehicleIdentifierNotFound)
342	            return
343	        }
344	        let result = self.refreshRealTimeCarKeySessionState(carKeySession: carkeySession)
345	        self.state = result.0
346	        if result.1 != .None {
347	            complete(result.1)
348	            return
349	        }
350	        Task.detached(priority: .userInitiated) {
351	            do {
352	                let result = try await CarKeySessionAccesser.withTimeout(seconds: timeOut) {
353	                    try await carkeySession.sendPassthroughData(data, toVehicle: self.vehicleIdentifier)
354	                }
355	                complete(.None)
356	                Log.i(tag: "carKeySession", "Data sent successfully.")
357	            } catch CarKeySessionError.TaskTimedOut {
358	                complete(.TaskTimedOut)
359	                Log.i("carKeySession", "sendPassthroughtData timeout")
360	            } catch {
361	                Log.i(tag: "carKeySession", "Failed to send data: \(error.localizedDescription)")
362	                if let carKeyError = error as? CarKeyErrorCode {
363	                    if carKeyError == .ClientInBackground {
364	                        complete(.ClientInBackground)
365	                    } else if carKeyError == .Internal {
366	                        complete(.Unknown)
367	                    } else if carKeyError == .VehicleNotConnected {
368	                        complete(.BleIsNotConnected)
369	                        self.state = .NotConnected
370	                    } else if carKeyError == .AnotherRequestInProgress {
371	                        complete(.AnotherRequestInProgress)
372	                    } else if carKeyError == .SessionNotActive {
373	                        complete(.SessionNotActive)
374	                    } else if carKeyError == .MessageTooLong {
375	                        complete(.MessageTooLong)
376	                    } else if carKeyError == .SecurityViolation {
377	                        complete(.SecurityViolation)
378	                    } else if carKeyError == .RequestTimedOut {
379	                        complete(.RequestTimedOut)
380	                    } else {
381	                        complete(.Unknown)
382	                    }
383	                } else {
384	                    complete(.Unknown)
385	                }
386	            }
387	        }
388	    }
389	    
390	    public func getLocalKeyPollingSwitchState(complete: @escaping (CarKeyPollingSwitchState, CarKeySessionError) -> Void) {
391	        if let session = self.carKeySession {
392	            do {
393	                let on = try session.isPassiveEntryAvailable(forVehicle: self.vehicleIdentifier)
394	                Log.i(tag: "carKeySession", "get passive entry on is \(on)")
395	                if on {
396	                    complete(.On,.None)
397	                } else {
398	                    complete(.Close,.None)
399	                }
400	            } catch {
401	                Log.i(tag: "carKeySession", "get passive entry error: \(error.localizedDescription)")
402	                complete(.Unknown,.Unknown)
403	            }
404	        } else {
405	            complete(.Unknown,.SessionNotActive)
406	        }
407	    }
