494	                        Log.i(tag: "carKeySession", "origin function \(functionId) data error:", error.localizedDescription)
495	                    }
496	                }
497	            }
498	            for functionId in vehicleDidUpdateReport.supportedFunctions {
499	                do {
500	                    let status =  try vehicleDidUpdateReport.status(for: functionId)
501	                    Log.i(tag: "carKeySession", "origin function \(functionId) status: \(status)")
502	                    let data = try vehicleDidUpdateReport.proprietaryData(for: functionId)
503	                    Log.i(tag: "carKeySession", "origin function \(functionId) data: \(data?.byteArray ?? [])")
504	                } catch {
505	                    Log.i(tag: "carKeySession", "origin function \(functionId) status error:", error.localizedDescription)
506	                    Log.i(tag: "carKeySession", "origin function \(functionId) data error:", error.localizedDescription)
