                do {
                    let status =  try vehicleDidUpdateReport.status(for: functionId)
                    Log.i(tag: "carKeySession", "origin function \(functionId) status: \(status)")
                    let data = try vehicleDidUpdateReport.proprietaryData(for: functionId)
                    Log.i(tag: "carKeySession", "origin function \(functionId) data: \(data?.byteArray ?? [])")
                } catch {
                    Log.i(tag: "carKeySession", "origin function \(functionId) status error:", error.localizedDescription)
                    Log.i(tag: "carKeySession", "origin function \(functionId) data error:", error.localizedDescription)
                }
            }
            self.supportedFunctions = vehicleDidUpdateReport.supportedFunctions
            Log.i(tag: "carKeySession", "vehicle supported functions updated: \(String(describing: self.supportedFunctions))")
        }

