150	        seconds: TimeInterval,
151	        operation: @escaping () async throws -> R,
152	        onSuccess: @escaping (R) -> Void,
153	        onTimeout: @escaping () -> Void,
154	        onError: @escaping (Error) -> Void
155	    ) -> Task<Void, Never> {
