229	    public func startCarKeySession(timeOut: TimeInterval, _ complete: @escaping ((CarKeySessionError) -> Void)) {
230	        if state == .Connecting {
231	            complete(CarKeySessionError.CarKeySessionIsConnecting)
232	            return
233	        }
234	        if state == .Disconnecting {
235	            complete(CarKeySessionError.CarKeySessionIsDisconnecting)
236	            return
237	        }
238	        self.state = .Connecting
239	        if let carKeySession = self.carKeySession {
240	            let result = refreshRealTimeCarKeySessionState(carKeySession: carKeySession)
241	            self.state = result.0
242	            complete(result.1)
243	        } else {
244	            Log.i(tag: "carKeySession", "startCarKeySession")
245	            var observeTimeOut: TimeInterval = timeOut
246	            if self.mockExcpetionType == .Block {
247	                observeTimeOut = 10000
248	            }
249	            let monitorTask = Task.detached { [weak self] in
250	                guard let self = self else {
251	                    return
252	                }
253	                try await Task.sleep(nanoseconds: UInt64((timeOut + 3) * 1_000_000_000))
254	                // 如果执行到这里，说明内层阻塞了
255	                Log.i(tag: "carKeySession", "block exception occurred！")
256	                self.carKeyEventDelegate?.reportBlockingException(data: CarKeyExceptionObj(cccVid: self.vehicleIdentifier, exceptionType: .Block, sessionError: .Block))
257	            }
258	            Log.i(tag: "carKeySession", "do carkeySession start")
259	            CarKeySessionAccesser.detachedWithTimeout(
260	                seconds: observeTimeOut,
261	                operation: {
262	                    if self.mockExcpetionType == .Block {
263	                        try await Task.sleep(nanoseconds: UInt64(observeTimeOut * 1_000_000_000))
264	                    } else if self.mockExcpetionType == .Timeout {
265	                        try await Task.sleep(nanoseconds: UInt64((observeTimeOut + 2) * 1_000_000_000))
266	                    } else if self.mockExcpetionType == .Error {
267	                        throw CarKeySessionError.RequestTimedOut
268	                    }
269	                    return try await CarKeyRemoteControl.start(delegate: self)
270	                },
271	                onSuccess: { result in
272	                    Log.i(tag: "carKeySession", "do carkeySession end")
273	                    self.carKeySession = result
274	                    let connectState = refreshRealTimeCarKeySessionState(carKeySession: result)
275	                    self.state = connectState.0
276	                    complete(connectState.1)
277	                    monitorTask.cancel()
278	                    self.carKeyEventDelegate?.reportBlockingException(data: CarKeyExceptionObj(cccVid: self.vehicleIdentifier, exceptionType: .None, sessionError: .None))
279	                },
