290	                    if let carKeyError = error as? CarKeyErrorCode {
291	                        if carKeyError == .ClientInBackground {
292	                            sessionError = .ClientInBackground
293	                        } else if carKeyError == .Internal {
294	                            sessionError = .Unknown
295	                        } else if carKeyError == .VehicleNotConnected {
296	                            sessionError = .BleIsNotConnected
297	                        } else if carKeyError == .SessionNotActive {
298	                            sessionError = .SessionNotActive
299	                        }  else if carKeyError == .SecurityViolation {
300	                            sessionError = .SecurityViolation
301	                        } else if carKeyError == .RequestTimedOut {
302	                            sessionError = .RequestTimedOut
303	                        } else {
304	                            sessionError = .Unknown
305	                        }
306	                    } else {
307	                        sessionError = .Unknown
308	                    }
