316	    func endCarKeySession(_ completion: ((CarKeySessionError) -> Void)?) {
317	        if state != CarKeySessionState.Connecting {
318	            let result = executeEndSessionOperation()
319	            completion?(result)
320	            return
321	        }
322	        self.endSessionCancellable = self.stateSubject
323	            .filter { $0 != CarKeySessionState.Connecting }
324	            .first()
325	            .sink { [weak self] newState in
326	                guard let self = self else {
327	                    completion?(.Unknown)
328	                    return
329	                }
330	                self.endSessionCancellable?.cancel()
331	                self.endSessionCancellable = nil
332	                let result = self.executeEndSessionOperation()
333	                completion?(result)
334	            }
335	    }
