337	    private func executeEndSessionOperation() -> CarKeySessionError {
338	        guard let carKeySession = self.carKeySession else {
339	            Log.i(tag: "carKeySession", "car key session is nil")
340	            self.state = .NotConnected
341	            return CarKeySessionError.CarKeySessionIsNil
342	        }
343	        self.state = .Disconnecting
344	        do {
345	            Log.i(tag: "carKeySession", "end key session")
346	            try carKeySession.end()
347	            self.carKeySession = nil
348	            self.state = .NotConnected
349	            return CarKeySessionError.None
350	        } catch let error as NSError {
351	            self.carKeySession = nil
352	            self.state = .NotConnected
353	            Log.i(tag: "carKeySession", "end session error occurred: \(error.localizedDescription)")
354	            return CarKeySessionError.Unknown
355	        }
356	    }
357	    
358	    public func sendPassthroughtData(data: Data, timeOut: TimeInterval, _ complete: @escaping ((CarKeySessionError) -> Void)) {
359	        guard let carkeySession = self.carKeySession else {
360	            complete(.CarKeySessionIsNil)
361	            return
362	        }
363	        if self.vehicleIdentifier == "" {
364	            complete(.VehicleIdentifierNotFound)
365	            return
366	        }
367	        let result = self.refreshRealTimeCarKeySessionState(carKeySession: carkeySession)
368	        self.state = result.0
369	        if result.1 != .None {
370	            complete(result.1)
371	            return
372	        }
373	        CarKeySessionAccesser.detachedWithTimeout(
374	            seconds: timeOut,
375	            operation: {
376	                try await carkeySession.sendPassthroughData(data, toVehicle: self.vehicleIdentifier)
377	            },
378	            onSuccess: { _ in
379	                complete(.None)
380	                Log.i(tag: "carKeySession", "Data sent successfully.")
381	            },
382	            onTimeout: {
383	                complete(.TaskTimedOut)
384	                Log.i("carKeySession", "sendPassthroughtData timeout")
385	            },
386	            onError: { error in
