enum CarKeySessionError: Int, Error, Codable, CustomStringConvertible {
    case None = 0;
    case CarKeySessionIsNil
    case BleIsNotConnected
    case VehicleIdentifierIsNotEqual
    case VehicleIdentifierNotFound
    case AnotherRequestInProgress
    case SessionNotActive
    case FunctionUnknown
    case SecurityViolation
    case MessageTooLong
    case RequestTimedOut
    case ClientInBackground
    case FeatureNotSupported
    case CarKeySessionIsConnecting
    case CarKeySessionIsDisconnecting
    case TaskTimedOut
    case Block
    case Unknown

     var description: String {
        switch self {
        case .None:
            return "None"
        case .CarKeySessionIsNil:
            return "CarKeySessionIsNil"
        case .BleIsNotConnected:
            return "BleIsNotConnected"
        case .VehicleIdentifierIsNotEqual:
            return "VehicleIdentifierIsNotEqual"
        case .VehicleIdentifierNotFound:
            return "VehicleIdentifierNotFound"
        case .AnotherRequestInProgress:
            return "AnotherRequestInProgress"
        case .SessionNotActive:
            return "SessionNotActive"
        case .FunctionUnknown:
            return "FunctionUnknown"
        case .SecurityViolation:
            return "SecurityViolation"
        case .MessageTooLong:
            return "MessageTooLong"
        case .RequestTimedOut:
            return "RequestTimedOut"
        case .ClientInBackground:
            return "ClientInBackground"
        case .FeatureNotSupported:
            return "FeatureNotSupported"
        case .CarKeySessionIsConnecting:
            return "CarKeySessionIsConnecting"
        case .CarKeySessionIsDisconnecting:
            return "CarKeySessionIsDisconnecting"
        case .TaskTimedOut:
            return "TaskTimedOut"
        case .Block:
            return "Block"
        case .Unknown:
            return "Unknown"
        }
    }
}

enum CarKeySessionState: Int, CustomStringConvertible {
    case NotConnected = 0
    case Disconnecting
    case Connecting
    case Connected

    var description: String {
        switch self {
        case .NotConnected:
            return "NotConnected"
        case .Disconnecting:
            return "Disconnectting"
        case .Connecting:
            return "Connecting"
        case .Connected:
            return "Connected"
        }
    }
}

@objc(XPCarKeyPollingSwitchState)
public enum CarKeyPollingSwitchState: Int {
    case Unknown = 0 //只有在前台Carkey蓝牙连接上才可以知道开关状态，未连上是返回Unknown
    case Close
    case On

    var description: String {
        switch self {
        case .Unknown:
            return "Unknown"
        case .Close:
            return "Close"
        case .On:
