30	    func addCarKeyStateObserver() {
31	        self.carKeySession.stateSubject.sink {[weak self] state in
32	            guard let self = self else {
33	                Log.i(tag: "carKeySession", "self is deallocated")
34	                return
35	            }
36	            Log.i(tag: "carKeySession", "carkey蓝牙连接状态：", state)
37	            if state == .NotConnected {
38	                self.state = .NotConnected
39	                self.disconnect()
40	                NotificationCenter.default.post(name: VehicleNotification.kGetCarKeyPassiveEntrySwitchResult, object: nil, userInfo: ["pollingState": CarKeyPollingSwitchState.Unknown.rawValue, "error": CarKeySessionError.BleIsNotConnected.rawValue])
41	            } else if state == .Connecting {
42	                self.state = .Connecting
43	            } else if state == .Connected {
44	                self.state = .Available
45	                self.carKeySession.getLocalKeyPollingSwitchState { state, error in
46	                    NotificationCenter.default.post(name: VehicleNotification.kGetCarKeyPassiveEntrySwitchResult, object: nil, userInfo: ["pollingState": state.rawValue, "error": error.rawValue])
47	                }
48	            }
49	        }.store(in: &cancellables)
50	    }
51	    
52	    deinit {
53	        Log.i("蓝牙 BLEHandler.deinit mac:", name)
54	        disconnect()
55	    }
56	    
57	    override func connect() {
58	        guard self.state == .NotConnected else {
59	            Log.i(tag: "carKeySession", "state is not notConnected")
60	            return
61	        }
62	        self.carKeySession.startCarKeySession(timeOut: 6) { [weak self] error in
63	            guard let self = self else {
64	                Log.i(tag: "carKeySession", "self is deallocated")
65	                return
66	            }
67	            Log.i(tag: "carKeySession", "startCarKeySession error:", error)
68	        }
69	    }
