72	        Log.i("bleDisconnect mac:", name)
73	        self.bleSendFlow?.cancelQueueAllTask()
74	        self.bleSendFlow = nil
75	        self.carKeySession.endCarKeySession { error in
76	            Log.i(tag: "carKeySession", "endCarKeySession error:", error)
77	        }
78	        self.state = .NotConnected
79	    }
