93	        let state = self.carKeySession.getRealTimeCarKeySessionState()
94	        if state == .NotConnected {
95	            return .NotConnected
96	        } else if state == .Connecting {
97	            return .Connecting
98	        } else if state == .Connected {
99	            return .Available
100	        } else {
101	            return .NotConnected
