    case AnotherRequestInProgress
    case SessionNotActive
    case FunctionUnknown
    case SecurityViolation
    case MessageTooLong
    case RequestTimedOut
    case ClientInBackground
    case FeatureNotSupported
    case CarKeySessionIsConnecting
    case CarKeySessionIsDisconnecting
    case TaskTimedOut
    case Block
    case Unknown

     var description: String {
        switch self {
        case .None:
            return "None"
        case .CarKeySessionIsNil:
            return "CarKeySessionIsNil"
        case .BleIsNotConnected:
            return "BleIsNotConnected"
        case .VehicleIdentifierIsNotEqual:
            return "VehicleIdentifierIsNotEqual"
        case .VehicleIdentifierNotFound:
            return "VehicleIdentifierNotFound"
        case .AnotherRequestInProgress:
            return "AnotherRequestInProgress"
        case .SessionNotActive:
            return "SessionNotActive"
        case .FunctionUnknown:
            return "FunctionUnknown"
        case .SecurityViolation:
            return "SecurityViolation"
        case .MessageTooLong:
            return "MessageTooLong"
        case .RequestTimedOut:
            return "RequestTimedOut"
        case .ClientInBackground:
            return "ClientInBackground"
        case .FeatureNotSupported:
            return "FeatureNotSupported"
        case .CarKeySessionIsConnecting:
            return "CarKeySessionIsConnecting"
        case .CarKeySessionIsDisconnecting:
            return "CarKeySessionIsDisconnecting"
        case .TaskTimedOut:
            return "TaskTimedOut"
        case .Block:
            return "Block"
        case .Unknown:
