        }
    }
}

enum CarKeySessionState: Int, CustomStringConvertible {
    case NotConnected = 0
    case Disconnecting
    case Connecting
    case Connected

    var description: String {
        switch self {
        case .NotConnected:
            return "NotConnected"
        case .Disconnecting:
            return "Disconnectting"
        case .Connecting:
            return "Connecting"
        case .Connected:
            return "Connected"
        }
    }
}

@objc(XPCarKeyPollingSwitchState)
public enum CarKeyPollingSwitchState: Int {
    case Unknown = 0 //只有在前台Carkey蓝牙连接上才可以知道开关状态，未连上是返回Unknown
    case Close
    case On

