129	    /// 在 detached task 中执行带超时的异步操作，结果通过 completion 回调
130	    @discardableResult
131	    static func detachedWithTimeout<R>(
132	        seconds: TimeInterval,
133	        operation: @escaping () async throws -> R,
134	        onSuccess: @escaping (R) -> Void,
135	        onTimeout: @escaping () -> Void,
136	        onError: @escaping (Error) -> Void
137	    ) -> Task<Void, Never> {
138	        Task.detached(priority: .userInitiated) {
139	            do {
140	                let result = try await withThrowingTaskGroup(of: R.self) { group in
141	                    group.addTask { try await operation() }
142	                    group.addTask {
143	                        try await Task.sleep(nanoseconds: UInt64(seconds * 1_000_000_000))
144	                        throw CarKeySessionError.TaskTimedOut
145	                    }
146	                    let result = try await group.next()!
147	                    group.cancelAll()
148	                    return result
149	                }
150	                onSuccess(result)
151	            } catch CarKeySessionError.TaskTimedOut {
152	                onTimeout()
153	            } catch {
154	                onError(error)
155	            }
156	        }
157	    }
