231	        } else {
232	            Log.i(tag: "carKeySession", "startCarKeySession")
233	            var observeTimeOut: TimeInterval = timeOut
234	            if self.mockExcpetionType == .Block {
235	                observeTimeOut = 10000
236	            }
237	            let monitorTask = Task.detached { [weak self] in
238	                guard let self = self else {
239	                    return
240	                }
241	                try await Task.sleep(nanoseconds: UInt64((timeOut + 3) * 1_000_000_000))
242	                // 如果执行到这里，说明内层阻塞了
243	                Log.i(tag: "carKeySession", "block exception occurred！")
244	                self.carKeyEventDelegate?.reportBlockingException(data: CarKeyExceptionObj(cccVid: self.vehicleIdentifier, exceptionType: .Block, sessionError: .Block))
245	            }
246	            Log.i(tag: "carKeySession", "do carkeySession start")
247	            CarKeySessionAccesser.detachedWithTimeout(
248	                seconds: observeTimeOut,
249	                operation: { [weak self] in
250	                    guard let self = self else {
251	                        throw CarKeySessionError.Unknown
252	                    }
253	                    if self.mockExcpetionType == .Block {
254	                        try await Task.sleep(nanoseconds: UInt64(observeTimeOut * 1_000_000_000))
255	                    } else if self.mockExcpetionType == .Timeout {
256	                        try await Task.sleep(nanoseconds: UInt64((observeTimeOut + 2) * 1_000_000_000))
257	                    } else if self.mockExcpetionType == .Error {
258	                        throw CarKeySessionError.RequestTimedOut
259	                    }
260	                    return try await CarKeyRemoteControl.start(delegate: self)
261	                },
262	                onSuccess: { [weak self] result in
263	                    guard let self = self else { return }
264	                    Log.i(tag: "carKeySession", "do carkeySession end")
265	                    self.carKeySession = result
266	                    let connectState = self.refreshRealTimeCarKeySessionState(carKeySession: result)
267	                    self.state = connectState.0
268	                    complete(connectState.1)
269	                    monitorTask.cancel()
270	                    self.carKeyEventDelegate?.reportBlockingException(data: CarKeyExceptionObj(cccVid: self.vehicleIdentifier, exceptionType: .None, sessionError: .None))
271	                },
272	                onTimeout: { [weak self] in
273	                    Log.i("carKeySession", "start carkeySession timeout")
274	                    monitorTask.cancel()
275	                    complete(.TaskTimedOut)
276	                    guard let self = self else { return }
277	                    self.carKeyEventDelegate?.reportBlockingException(data: CarKeyExceptionObj(cccVid: self.vehicleIdentifier, exceptionType: .Timeout, sessionError: .TaskTimedOut))
278	                },
279	                onError: { [weak self] error in
280	                    Log.i(tag: "carKeySession", "start session error occurred: \(error.localizedDescription)")
281	                    monitorTask.cancel()
282	                    var sessionError: CarKeySessionError = .Unknown
283	                    if let carKeyError = error as? CarKeyErrorCode {
284	                        if carKeyError == .ClientInBackground {
285	                            sessionError = .ClientInBackground
286	                        } else if carKeyError == .Internal {
287	                            sessionError = .Unknown
288	                        } else if carKeyError == .VehicleNotConnected {
289	                            sessionError = .BleIsNotConnected
290	                        } else if carKeyError == .SessionNotActive {
291	                            sessionError = .SessionNotActive
292	                        }  else if carKeyError == .SecurityViolation {
293	                            sessionError = .SecurityViolation
294	                        } else if carKeyError == .RequestTimedOut {
295	                            sessionError = .RequestTimedOut
296	                        } else {
297	                            sessionError = .Unknown
298	                        }
299	                    } else {
300	                        sessionError = .Unknown
301	                    }
302	                    complete(sessionError)
303	                    guard let self = self else { return }
304	                    self.carKeyEventDelegate?.reportBlockingException(data: CarKeyExceptionObj(cccVid: self.vehicleIdentifier, exceptionType: .Error, sessionError: sessionError))
305	                }
306	            )
307	        }
308	    }
