310	    func endCarKeySession(_ completion: ((CarKeySessionError) -> Void)?) {
311	        if state != CarKeySessionState.Connecting {
312	            let result = executeEndSessionOperation()
313	            completion?(result)
314	            return
315	        }
316	        self.endSessionCancellable = self.stateSubject
317	            .filter { $0 != CarKeySessionState.Connecting }
318	            .first()
319	            .sink { [weak self] newState in
320	                guard let self = self else {
321	                    completion?(.Unknown)
322	                    return
323	                }
324	                self.endSessionCancellable?.cancel()
325	                self.endSessionCancellable = nil
326	                let result = self.executeEndSessionOperation()
327	                completion?(result)
328	            }
329	    }
