331	    private func executeEndSessionOperation() -> CarKeySessionError {
332	        guard let carKeySession = self.carKeySession else {
333	            Log.i(tag: "carKeySession", "car key session is nil")
334	            self.state = .NotConnected
335	            return CarKeySessionError.CarKeySessionIsNil
336	        }
337	        self.state = .Disconnecting
338	        do {
339	            Log.i(tag: "carKeySession", "end key session")
340	            try carKeySession.end()
341	            self.carKeySession = nil
342	            self.state = .NotConnected
343	            return CarKeySessionError.None
344	        } catch let error as NSError {
345	            self.carKeySession = nil
346	            self.state = .NotConnected
347	            Log.i(tag: "carKeySession", "end session error occurred: \(error.localizedDescription)")
348	            return CarKeySessionError.Unknown
349	        }
